package sn.gestionimmobiliere.backend.billing.infrastructure;
import java.time.LocalDate;import java.util.*;import org.springframework.data.domain.*;import org.springframework.data.jpa.repository.*;import org.springframework.data.repository.query.Param;import sn.gestionimmobiliere.backend.billing.domain.*;
public interface RentChargeRepository extends JpaRepository<RentCharge,UUID>{Page<RentCharge> findAllByOrganizationId(UUID org,Pageable p);Optional<RentCharge> findByIdAndOrganizationId(UUID id,UUID org);List<RentCharge> findAllByOrganizationIdAndStatusIn(UUID org,Collection<ChargeStatus> statuses);boolean existsByOrganizationIdAndLeaseIdAndPeriodStart(UUID org,UUID leaseId,LocalDate periodStart);@Query("select coalesce(sum(c.amountDue),0) from RentCharge c where c.organizationId=:org")Long totalDue(@Param("org")UUID org);@Query("select coalesce(sum(c.amountPaid),0) from RentCharge c where c.organizationId=:org")Long totalPaid(@Param("org")UUID org);}
